\AxiomC{\ensuremath{[q \lor  r]^2\vphantom{|}}}
\AxiomC{\ensuremath{p\vphantom{|}}}
\AxiomC{\ensuremath{[q]^1\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  I:\quad }}
\BinaryInfC{\ensuremath{p \land  q\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \lor  I_l:\quad }}
\UnaryInfC{\ensuremath{(p \land  q) \lor  r\vphantom{|}}}
